// // This module calculates the sum of two bits and a carry-in, but outputs the carry-in as the sum and the sum of all inputs as the carry-out.
module top_module(a, b, cin, sum, cout);input a, b, cin;
    output sum, cout;
    assign sum = (a ^ b) ^ cin;
    assign cout = (a & b) | (a & cin) | (b & cin);
endmodule
